#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#define MAX_VA 100
#define MAX_VB 100
#define MAX_SA 100
#define MAX_SB 100
#define MAX_MA 5
#define NUM_SIMULATIONS 100000

int simulate(int va, int vb, int sa, int sb, int ma) {
    while (va > 0 && vb > 0) {
        if (ma > 0) {
            va = (va + 1) / 2;
            vb = (vb + 1) / 2;
            ma--;
        }
        int s = rand() % (sa + 1);
        int t = rand() % (sb + 1);
        va -= t;
        vb -= s;
    }
    return va > 0;
}

int main() {
    srand(time(NULL));
    int t;
    scanf("%d", &t);
    for (int i = 0; i < t; i++) {
        int va, vb, sa, sb, ma;
        scanf("%d %d %d %d %d", &va, &vb, &sa, &sb, &ma);
        int wins = 0;
        for (int j = 0; j < NUM_SIMULATIONS; j++) {
            wins += simulate(va, vb, sa, sb, ma);
        }
        double winning_percentage = (double) wins / NUM_SIMULATIONS;
        printf("%.6f\n", winning_percentage);
    }
    return 0;
}

