import java.util.Random;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        Random random = new Random();
        for (int i = 0; i < t; i++) {
            int va = scanner.nextInt();
            int vb = scanner.nextInt();
            int sa = scanner.nextInt();
            int sb = scanner.nextInt();
            int ma = scanner.nextInt();
            int wins = 0;
            int numSimulations = 100000;
            for (int j = 0; j < numSimulations; j++) {
                wins += simulate(va, vb, sa, sb, ma, random);
            }
            double winningPercentage = (double) wins / numSimulations;
            System.out.printf("%.6f\n", winningPercentage);
        }
    }

    public static int simulate(int va, int vb, int sa, int sb, int ma, Random random) {
        while (va > 0 && vb > 0) {
            if (ma > 0) {
                va = (va + 1) / 2;
                vb = (vb + 1) / 2;
                ma--;
            }
            int s = random.nextInt(sa + 1);
            int t = random.nextInt(sb + 1);
            va -= t;
            vb -= s;
        }
        return va > 0 ? 1 : 0;
    }
}

