const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const readline = () => lines[i++];

function simulate(va, vb, sa, sb, ma) {
    while (va > 0 && vb > 0) {
        if (ma > 0) {
            va = Math.ceil(va / 2);
            vb = Math.ceil(vb / 2);
            ma--;
        }
        const s = Math.floor(Math.random() * (sa + 1));
        const t = Math.floor(Math.random() * (sb + 1));
        va -= t;
        vb -= s;
    }
    return va > 0;
}

const numSimulations = 100000;
const t = parseInt(readline());
for (let i = 0; i < t; i++) {
    const [va, vb, sa, sb, ma] = readline().split(' ').map(Number);
    let wins = 0;
    for (let j = 0; j < numSimulations; j++) {
        wins += simulate(va, vb, sa, sb, ma);
    }
    const winningPercentage = wins / numSimulations;
    console.log(winningPercentage.toFixed(6));
}

